---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <Header lang={lang} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
  </body>
</html>

---
/**
 * Site header with responsive nav and mobile hamburger.
 * Uses CSS custom properties only — no hardcoded colors/sizes.
 */
import { getNavLinks, type Lang } from '../lib/navigation';

interface Props {
  lang?: Lang;
}

const { lang = 'en' } = Astro.props;
const navLinks = getNavLinks(lang);
const logoHref = lang === 'zh' ? '/zh' : '/';
const logoText = lang === 'zh' ? '伊的家' : 'FICCC';
const logoLabel = lang === 'zh' ? '伊的家 — 首頁' : 'FICCC — Home';
const langToggleLabel = lang === 'zh' ? '中文 / EN' : 'EN / 中文';
const langToggleHref = lang === 'zh' ? '/' : '/zh';
---

<header class="site-header">
  <div class="header-inner">
    <a href={logoHref} class="logo" aria-label={logoLabel}>
      <span class="logo-text">{logoText}</span>
    </a>

    <button
      class="hamburger"
      type="button"
      aria-expanded="false"
      aria-controls="nav-menu"
      aria-label="Toggle navigation menu"
    >
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
    </button>

    <nav id="nav-menu" class="nav" aria-label="Main navigation">
      <ul class="nav-list" role="list">
        {navLinks.map((link) => (
          <li><a href={link.href} class="nav-link">{link.label}</a></li>
        ))}
      </ul>
      <a href={langToggleHref} class="lang-toggle" aria-label={lang === 'zh' ? '切換至英文' : 'Switch to Chinese'}>
        {langToggleLabel}
      </a>
    </nav>
  </div>
</header>

<style>
  .site-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background-color: var(--color-bg);
    border-bottom: 1px solid var(--color-stone);
  }

  .header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: var(--max-width);
    margin-inline: auto;
    padding: var(--space-4) var(--space-6);
  }

  /* Logo */
  .logo {
    text-decoration: none;
    color: var(--color-ink);
  }
  .logo-text {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    font-weight: 700;
    letter-spacing: 0.04em;
  }

  /* Desktop nav */
  .nav {
    display: flex;
    align-items: center;
    gap: var(--space-6);
  }
  .nav-list {
    display: flex;
    list-style: none;
    gap: var(--space-6);
  }
  .nav-link {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 500;
    color: var(--color-body);
    text-decoration: none;
    padding: var(--space-1) 0;
    border-bottom: 2px solid transparent;
    transition: border-color var(--transition), color var(--transition);
  }
  .nav-link:hover,
  .nav-link:focus-visible {
    color: var(--color-terracotta);
    border-bottom-color: var(--color-terracotta);
  }
  .nav-link:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 4px;
    border-radius: var(--radius-sm);
  }

  /* Language toggle */
  .lang-toggle {
    font-family: var(--font-body);
    font-size: var(--text-xs);
    font-weight: 600;
    color: var(--color-ink);
    background: none;
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-sm);
    padding: var(--space-1) var(--space-3);
    cursor: pointer;
    transition: background-color var(--transition), color var(--transition);
  }
  .lang-toggle:hover,
  .lang-toggle:focus-visible {
    background-color: var(--color-terracotta);
    color: var(--color-bg);
  }
  .lang-toggle:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  /* Hamburger — hidden on desktop */
  .hamburger {
    display: none;
    flex-direction: column;
    justify-content: center;
    gap: 5px;
    background: none;
    border: none;
    cursor: pointer;
    padding: var(--space-2);
    z-index: 110;
  }
  .hamburger-bar {
    display: block;
    width: 24px;
    height: 2px;
    background-color: var(--color-ink);
    border-radius: 1px;
    transition: transform var(--transition), opacity var(--transition);
  }
  .hamburger:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: var(--radius-sm);
  }

  /* Hamburger open state */
  .hamburger[aria-expanded='true'] .hamburger-bar:nth-child(1) {
    transform: translateY(7px) rotate(45deg);
  }
  .hamburger[aria-expanded='true'] .hamburger-bar:nth-child(2) {
    opacity: 0;
  }
  .hamburger[aria-expanded='true'] .hamburger-bar:nth-child(3) {
    transform: translateY(-7px) rotate(-45deg);
  }

  /* Mobile: ≤767px */
  @media (max-width: 767px) {
    .hamburger {
      display: flex;
    }

    .nav {
      position: fixed;
      top: 0;
      right: 0;
      bottom: 0;
      width: min(75vw, 20rem);
      flex-direction: column;
      align-items: flex-start;
      padding: var(--space-16) var(--space-6) var(--space-8);
      background-color: var(--color-bg);
      border-left: 1px solid var(--color-stone);
      box-shadow: -4px 0 24px rgba(0, 0, 0, 0.08);
      transform: translateX(100%);
      transition: transform var(--transition);
      z-index: 105;
    }
    .nav.is-open {
      transform: translateX(0);
    }

    .nav-list {
      flex-direction: column;
      gap: var(--space-4);
    }
    .nav-link {
      font-size: var(--text-base);
    }
  }
</style>

<script>
  const btn = document.querySelector('.hamburger') as HTMLButtonElement;
  const nav = document.querySelector('#nav-menu') as HTMLElement;

  if (btn && nav) {
    btn.addEventListener('click', () => {
      const expanded = btn.getAttribute('aria-expanded') === 'true';
      btn.setAttribute('aria-expanded', String(!expanded));
      nav.classList.toggle('is-open', !expanded);
    });

    // Close on Escape
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && btn.getAttribute('aria-expanded') === 'true') {
        btn.setAttribute('aria-expanded', 'false');
        nav.classList.remove('is-open');
        btn.focus();
      }
    });
  }
</script>

---
interface Props {
  title: string;
  description?: string;
  canonicalUrl?: string;
  ogImage?: string;
  ogType?: string;
  lang?: string;
  jsonLd?: Record<string, unknown>;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  canonicalUrl,
  ogImage = '/og-default.png',
  ogType = 'website',
  lang = 'en',
  jsonLd,
} = Astro.props;

const siteUrl = Astro.site ?? new URL('https://ficcc.org');
const canonical = canonicalUrl ?? new URL(Astro.url.pathname, siteUrl).href;
const absoluteOgImage = new URL(ogImage, siteUrl).href;

const localeMap: Record<string, string> = {
  en: 'en_US',
  zh: 'zh_CN',
};
const ogLocale = localeMap[lang] ?? 'en_US';

const defaultJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'Church',
  name: 'FICCC — Fellowship of Ithaca Chinese Christians Church',
  description,
  url: canonical,
};

const structuredData = jsonLd ?? defaultJsonLd;
---

<title>{title}</title>
<meta name="description" content={description} />
<link rel="canonical" href={canonical} />

<!-- Open Graph -->
<meta property="og:title" content={title} />
<meta property="og:description" content={description} />
<meta property="og:url" content={canonical} />
<meta property="og:image" content={absoluteOgImage} />
<meta property="og:type" content={ogType} />
<meta property="og:locale" content={ogLocale} />

<!-- Twitter Card -->
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:title" content={title} />
<meta name="twitter:description" content={description} />
<meta name="twitter:image" content={absoluteOgImage} />

<!-- JSON-LD Structured Data -->
<script type="application/ld+json" set:html={JSON.stringify(structuredData)} />

/**
 * Shared navigation configuration for Header and Footer.
 * Returns language-appropriate labels and hrefs.
 */

export type Lang = 'en' | 'zh';

export interface NavLink {
  label: string;
  href: string;
}

const navLinksEN: NavLink[] = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Ministries', href: '/ministries' },
  { label: 'Sermons', href: '/sermons' },
  { label: 'Contact', href: '/contact' },
];

const navLinksZH: NavLink[] = [
  { label: '首頁', href: '/zh' },
  { label: '關於我們', href: '/zh/about' },
  { label: '團契', href: '/zh/ministries' },
  { label: '講道', href: '/zh/sermons' },
  { label: '聯絡我們', href: '/zh/contact' },
];

export function getNavLinks(lang: Lang = 'en'): NavLink[] {
  return lang === 'zh' ? navLinksZH : navLinksEN;
}

const footerNavEN: NavLink[] = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Ministries', href: '/ministries' },
  { label: 'Sermons', href: '/sermons' },
  { label: 'Contact', href: '/contact' },
];

const footerNavZH: NavLink[] = [
  { label: '首頁', href: '/zh' },
  { label: '關於我們', href: '/zh/about' },
  { label: '團契', href: '/zh/ministries' },
  { label: '講道', href: '/zh/sermons' },
  { label: '聯絡我們', href: '/zh/contact' },
];

export function getFooterNav(lang: Lang = 'en'): NavLink[] {
  return lang === 'zh' ? footerNavZH : footerNavEN;
}

/** Service times content by language. */
export interface ServiceTime {
  label: string;
}

export function getServiceTimes(lang: Lang = 'en'): { heading: string; items: ServiceTime[] } {
  if (lang === 'zh') {
    return {
      heading: '聚會時間',
      items: [
        { label: '主日崇拜：上午 10:00' },
        { label: '主日學：上午 11:30' },
        { label: '週五團契：晚上 7:30' },
      ],
    };
  }
  return {
    heading: 'Service Times',
    items: [
      { label: 'Sunday Worship: 10:00 AM' },
      { label: 'Sunday School: 11:30 AM' },
      { label: 'Friday Fellowship: 7:30 PM' },
    ],
  };
}

/**
 * Asymmetric route map: pages where EN and ZH paths differ beyond the /zh prefix.
 * Key = source path, Value = counterpart path.
 */
const ASYMMETRIC_ROUTES: Record<string, string> = {
  '/visit': '/zh/sundays',
  '/zh/sundays': '/visit',
};

/**
 * Pages that exist only in one language and have no counterpart.
 * These fall back to the other language's homepage.
 */
const NO_COUNTERPART = ['/resources', '/styleguide', '/admin', '/404'];

/**
 * Given a pathname and current language, return the URL for the same page
 * in the other language. Handles asymmetric routes, prefix swapping,
 * trailing-slash normalization, and falls back to the other-language homepage
 * when no counterpart exists.
 */
export function getAlternateUrl(pathname: string, currentLang: Lang): string {
  // Normalize: strip trailing slash (but keep "/" as-is)
  const normalized = pathname.length > 1 && pathname.endsWith('/')
    ? pathname.slice(0, -1)
    : pathname;

  // Check asymmetric routes first
  if (ASYMMETRIC_ROUTES[normalized]) {
    return ASYMMETRIC_ROUTES[normalized];
  }

  // Check if this page has no counterpart → fall back to other-language homepage
  if (NO_COUNTERPART.some((p) => normalized === p || normalized.startsWith(p + '/'))) {
    return currentLang === 'en' ? '/zh' : '/';
  }

  if (currentLang === 'en') {
    // EN → ZH: prepend /zh
    return normalized === '/' ? '/zh' : `/zh${normalized}`;
  }

  // ZH → EN: strip /zh prefix
  if (normalized === '/zh') {
    return '/';
  }
  return normalized.replace(/^\/zh/, '');
}

/** Church name by language for copyright, logos, etc. */
export function getChurchName(lang: Lang = 'en'): string {
  return lang === 'zh'
    ? '伊的家華人基督教會'
    : 'First Ithaca Chinese Christian Church';
}

